CREATE TABLE class_schedule (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, schedule_date DATE NOT NULL, day_of_week VARCHAR(20) DEFAULT NULL, start_time TIME(0) WITHOUT TIME ZONE NOT NULL, end_time TIME(0) WITHOUT TIME ZONE NOT NULL, course_code VARCHAR(50) NOT NULL, section VARCHAR(50) DEFAULT NULL, faculty_name VARCHAR(255) DEFAULT NULL, faculty_email VARCHAR(180) DEFAULT NULL, source VARCHAR(255) DEFAULT NULL, import_batch_id VARCHAR(64) DEFAULT NULL, schedule_identifier VARCHAR(64) DEFAULT NULL, is_relocated BOOLEAN DEFAULT false NOT NULL, status VARCHAR(50) DEFAULT NULL, start_date DATE DEFAULT NULL, end_date DATE DEFAULT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, updated_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, facility_id INT NOT NULL, previous_facility_id INT DEFAULT NULL, faculty_user_id INT DEFAULT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_EEF6DAABA7014910 ON class_schedule (facility_id);
CREATE INDEX IDX_EEF6DAAB15CB427A ON class_schedule (previous_facility_id);
CREATE INDEX IDX_EEF6DAABE67D05CF ON class_schedule (faculty_user_id);
CREATE TABLE class_schedule_notification_log (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, recipient_email VARCHAR(180) NOT NULL, actor_role_label VARCHAR(30) NOT NULL, channels VARCHAR(30) NOT NULL, message TEXT NOT NULL, email_sent BOOLEAN DEFAULT false NOT NULL, in_app_sent BOOLEAN DEFAULT false NOT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, class_schedule_id INT NOT NULL, notified_by_id INT NOT NULL, faculty_user_id INT DEFAULT NULL, previous_facility_id INT DEFAULT NULL, new_facility_id INT DEFAULT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_48B6915C9C650DE3 ON class_schedule_notification_log (class_schedule_id);
CREATE INDEX IDX_48B6915CE97D56E9 ON class_schedule_notification_log (notified_by_id);
CREATE INDEX IDX_48B6915CE67D05CF ON class_schedule_notification_log (faculty_user_id);
CREATE INDEX IDX_48B6915C15CB427A ON class_schedule_notification_log (previous_facility_id);
CREATE INDEX IDX_48B6915C350EF868 ON class_schedule_notification_log (new_facility_id);
CREATE TABLE facility (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, name VARCHAR(255) NOT NULL, capacity INT NOT NULL, description TEXT DEFAULT NULL, image VARCHAR(255) DEFAULT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, available_for_reservation BOOLEAN NOT NULL, updated_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, parent_id INT DEFAULT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_105994B2727ACA70 ON facility (parent_id);
CREATE TABLE facility_image (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, path VARCHAR(255) NOT NULL, caption VARCHAR(255) DEFAULT NULL, position INT NOT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, facility_id INT NOT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_96A23835A7014910 ON facility_image (facility_id);
CREATE TABLE facility_schedule_block (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, title VARCHAR(255) NOT NULL, type VARCHAR(50) NOT NULL, block_date DATE NOT NULL, start_time TIME(0) WITHOUT TIME ZONE NOT NULL, end_time TIME(0) WITHOUT TIME ZONE NOT NULL, source VARCHAR(255) DEFAULT NULL, schedule_identifier VARCHAR(255) DEFAULT NULL, notes TEXT DEFAULT NULL, original_item_type VARCHAR(50) DEFAULT NULL, original_item_id INT DEFAULT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, facility_id INT NOT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_F7F766FAA7014910 ON facility_schedule_block (facility_id);
CREATE TABLE mentor_application (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, email VARCHAR(255) NOT NULL, first_name VARCHAR(100) DEFAULT NULL, middle_name VARCHAR(100) DEFAULT NULL, last_name VARCHAR(100) DEFAULT NULL, program_course VARCHAR(255) DEFAULT NULL, specialization VARCHAR(255) NOT NULL, reason TEXT DEFAULT NULL, current_profession VARCHAR(150) DEFAULT NULL, highest_education VARCHAR(150) DEFAULT NULL, mentoring_public_bio TEXT DEFAULT NULL, availability_time VARCHAR(255) DEFAULT NULL, supporting_documents JSON DEFAULT NULL, status VARCHAR(50) NOT NULL, valid_until TIMESTAMP(0) WITHOUT TIME ZONE DEFAULT NULL, admin_note TEXT DEFAULT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, updated_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, student_id INT NOT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_E001ECD7CB944F1A ON mentor_application (student_id);
CREATE TABLE mentor_availability (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, available_date DATE NOT NULL, start_time TIME(0) WITHOUT TIME ZONE NOT NULL, end_time TIME(0) WITHOUT TIME ZONE NOT NULL, is_booked BOOLEAN NOT NULL, mentor_id INT NOT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_CB274DDFDB403044 ON mentor_availability (mentor_id);
CREATE TABLE mentor_custom_request (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, message TEXT NOT NULL, status VARCHAR(50) NOT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, updated_at TIMESTAMP(0) WITHOUT TIME ZONE DEFAULT NULL, mentor_response TEXT DEFAULT NULL, full_name VARCHAR(255) DEFAULT NULL, department_course VARCHAR(255) DEFAULT NULL, preferred_expertise VARCHAR(255) DEFAULT NULL, preferred_schedule VARCHAR(255) DEFAULT NULL, assigned_mentor_name VARCHAR(255) DEFAULT NULL, assigned_mentor_expertise VARCHAR(255) DEFAULT NULL, available_dates VARCHAR(255) DEFAULT NULL, available_time VARCHAR(255) DEFAULT NULL, meeting_method VARCHAR(50) DEFAULT NULL, admin_instructions TEXT DEFAULT NULL, responded_at TIMESTAMP(0) WITHOUT TIME ZONE DEFAULT NULL, scheduled_date DATE DEFAULT NULL, scheduled_time VARCHAR(50) DEFAULT NULL, meeting_type VARCHAR(50) DEFAULT NULL, meeting_link VARCHAR(500) DEFAULT NULL, meeting_location VARCHAR(255) DEFAULT NULL, facility_id INT DEFAULT NULL, facility_name VARCHAR(255) DEFAULT NULL, facility_reserved_by VARCHAR(50) DEFAULT NULL, student_id INT NOT NULL, mentor_profile_id INT DEFAULT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_6986868CCB944F1A ON mentor_custom_request (student_id);
CREATE INDEX IDX_6986868C92E677D4 ON mentor_custom_request (mentor_profile_id);
CREATE TABLE mentoring_appointment (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, scheduled_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, status VARCHAR(50) NOT NULL, topic TEXT DEFAULT NULL, notes TEXT DEFAULT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, student_id INT NOT NULL, mentor_id INT NOT NULL, availability_id INT DEFAULT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_8538E640CB944F1A ON mentoring_appointment (student_id);
CREATE INDEX IDX_8538E640DB403044 ON mentoring_appointment (mentor_id);
CREATE INDEX IDX_8538E64061778466 ON mentoring_appointment (availability_id);
CREATE TABLE mentoring_audit_log (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, subject_type VARCHAR(30) NOT NULL, subject_id INT DEFAULT NULL, subject_label VARCHAR(120) NOT NULL, action VARCHAR(40) NOT NULL, previous_status VARCHAR(50) DEFAULT NULL, new_status VARCHAR(50) DEFAULT NULL, performed_by_name VARCHAR(60) DEFAULT NULL, performed_by_role VARCHAR(30) DEFAULT NULL, note TEXT DEFAULT NULL, logged_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, performed_by_id INT DEFAULT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_C8A22ECE2E65C292 ON mentoring_audit_log (performed_by_id);
CREATE INDEX idx_mentoring_audit_log_logged_at ON mentoring_audit_log (logged_at);
CREATE TABLE mentor_profile (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, display_name VARCHAR(255) NOT NULL, specialization VARCHAR(255) NOT NULL, bio TEXT DEFAULT NULL, education VARCHAR(255) DEFAULT NULL, availability_days JSON DEFAULT NULL, availability_start VARCHAR(100) DEFAULT NULL, availability_end VARCHAR(100) DEFAULT NULL, engagement_points INT NOT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, user_id INT NOT NULL, PRIMARY KEY (id));
CREATE UNIQUE INDEX UNIQ_185C512AA76ED395 ON mentor_profile (user_id);
CREATE TABLE notifications (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, type VARCHAR(50) NOT NULL, title VARCHAR(255) NOT NULL, message TEXT NOT NULL, status VARCHAR(20) NOT NULL, is_read BOOLEAN NOT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, reference_id INT DEFAULT NULL, user_id INT NOT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_6000B0D3A76ED395 ON notifications (user_id);
CREATE TABLE research_content (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, title VARCHAR(255) NOT NULL, type VARCHAR(50) NOT NULL, category VARCHAR(100) NOT NULL, tags VARCHAR(255) DEFAULT NULL, summary TEXT DEFAULT NULL, body TEXT DEFAULT NULL, file_path VARCHAR(255) DEFAULT NULL, embedded_link TEXT DEFAULT NULL, external_link TEXT DEFAULT NULL, visibility VARCHAR(30) NOT NULL, repository_type VARCHAR(100) DEFAULT NULL, authors TEXT DEFAULT NULL, abstract TEXT DEFAULT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, updated_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, author_id INT NOT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_676B80B3F675F31B ON research_content (author_id);
CREATE TABLE reservation (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, name VARCHAR(255) NOT NULL, event_name VARCHAR(255) DEFAULT NULL, email VARCHAR(255) NOT NULL, contact VARCHAR(20) NOT NULL, reservation_date TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, reservation_start_time TIME(0) WITHOUT TIME ZONE NOT NULL, reservation_end_time TIME(0) WITHOUT TIME ZONE NOT NULL, capacity INT NOT NULL, purpose TEXT DEFAULT NULL, status VARCHAR(50) NOT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, updated_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, rejection_reason VARCHAR(255) DEFAULT NULL, user_id INT NOT NULL, facility_id INT NOT NULL, suggested_facility_id INT DEFAULT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_42C84955A76ED395 ON reservation (user_id);
CREATE INDEX IDX_42C84955A7014910 ON reservation (facility_id);
CREATE INDEX IDX_42C8495568500A62 ON reservation (suggested_facility_id);
CREATE TABLE reservation_status_log (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, previous_status VARCHAR(50) NOT NULL, new_status VARCHAR(50) NOT NULL, actor_role_label VARCHAR(30) NOT NULL, action VARCHAR(30) NOT NULL, note TEXT DEFAULT NULL, changed_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, reservation_id INT NOT NULL, changed_by_id INT NOT NULL, PRIMARY KEY (id));
CREATE INDEX IDX_31FAF1D3B83297E7 ON reservation_status_log (reservation_id);
CREATE INDEX IDX_31FAF1D3828AD0A0 ON reservation_status_log (changed_by_id);
CREATE INDEX idx_reservation_status_log_changed_at ON reservation_status_log (changed_at);
CREATE TABLE specialization (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, name VARCHAR(255) NOT NULL, created_at TIMESTAMP(0) WITHOUT TIME ZONE NOT NULL, PRIMARY KEY (id));
CREATE TABLE "user" (id INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, email VARCHAR(180) NOT NULL, roles JSON NOT NULL, password VARCHAR(255) NOT NULL, is_verified BOOLEAN NOT NULL, verification_code VARCHAR(10) DEFAULT NULL, first_name VARCHAR(100) DEFAULT NULL, middle_name VARCHAR(100) DEFAULT NULL, last_name VARCHAR(100) DEFAULT NULL, degree VARCHAR(100) DEFAULT NULL, degree_name VARCHAR(255) DEFAULT NULL, specialization VARCHAR(255) DEFAULT NULL, profile_picture VARCHAR(255) DEFAULT NULL, PRIMARY KEY (id));
