UPDATE facility child
SET parent_id = parent.id
FROM facility parent
WHERE parent.name = 'Lounge Area'
AND child.name IN ('Lounge 1', 'Lounge 2', 'Lounge 3', 'Lounge 4')
AND child.parent_id IS NULL;

